parameters.jsCode:
// Postmark fires this webhook on bounce / spam-complaint / open / click /
// delivery / subscription events. We filter to the operationally-important
// ones: bounce, spam complaint, transient (deferred), and link-broken.
//
// Payload shape (Postmark v1 webhook format):
//   RecordType: 'Bounce' | 'SpamComplaint' | 'Delivery' | 'Open' | 'Click' | 'SubscriptionChange'
//   Type: 'HardBounce' | 'SoftBounce' | 'Transient' | ...
//   Email: recipient
//   Subject: original message subject
//   From: sender
//   BouncedAt / SpamComplaintAt: timestamp
//   Description: human-readable error
//   Details: technical error
//
// See https://postmarkapp.com/developer/webhooks for full schema.

const body = $json.body || {};
const recordType = (body.RecordType || '').toLowerCase();

let text = null;

if (recordType === 'bounce') {
  const bounceType = body.Type || 'Bounce';
  const isHard = bounceType.toLowerCase().includes('hard');
  const emoji = isHard ? ':x:' : ':warning:';
  const recip = body.Email || 'unknown';
  const subj = (body.Subject || '(no subject)').slice(0, 80);
  const when = body.BouncedAt || new Date().toISOString();
  const desc = (body.Description || body.Details || 'no description').slice(0, 200);
  text = `${emoji} **Postmark: ${bounceType}**\n` +
         `  Recipient: \`${recip}\`\n` +
         `  Subject: ${subj}\n` +
         `  When: ${when}\n` +
         `  Reason: ${desc}`;
  if (isHard) {
    text += `\n  :information_source: Hard bounce — Postmark has marked this address inactive. To unblock, visit Postmark → Servers → your-server → Activity → search the address → Reactivate.`;
  }
} else if (recordType === 'spamcomplaint') {
  const recip = body.Email || 'unknown';
  const subj = (body.Subject || '(no subject)').slice(0, 80);
  const when = body.SpamComplaintAt || new Date().toISOString();
  text = `:no_entry: **Postmark: Spam complaint**\n` +
         `  Recipient: \`${recip}\`\n` +
         `  Subject: ${subj}\n` +
         `  When: ${when}\n` +
         `  :warning: This recipient has reported your mail as spam. Postmark has suppressed future sends to this address. Investigate why — wrong list, bad content, or compromised sender?`;
} else if (recordType === 'subscriptionchange') {
  const recip = body.Recipient || body.Email || 'unknown';
  const supp = body.SuppressionReason || 'unknown reason';
  text = `:bell: **Postmark: Subscription change**\n` +
         `  Recipient: \`${recip}\`\n` +
         `  Reason: ${supp}`;
}
// We intentionally don't post for 'Delivery' (every successful send would
// flood the channel) or 'Open'/'Click' (high-volume tracking events).

if (!text) return [{ json: { skip: true, recordType } }];
return [{ json: { text, recordType } }];

parameters.responseBody:
={
  "ok": true,
  "posted": false,
  "recordType": {{JSON.stringify($json.recordType || 'unknown')}},
  "reason": "event ignored (delivery/open/click etc are high-volume — skipped)"
}
